  "refresh_mv_location_group": "CREATE OR REPLACE FUNCTION public.refresh_mv_location_group()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\nAS $function$\r\nbegin\r\n  refresh materialized view concurrently public.mv_location_group;\r\nend;\r\n$function$;",
  "refresh_mv_salary_type_median_ratio": "CREATE OR REPLACE FUNCTION public.refresh_mv_salary_type_median_ratio()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_salary_type_median_ratio;\r\nEND;\r\n$function$;",
  "refresh_mv_salary_weighted_ratio": "CREATE OR REPLACE FUNCTION public.refresh_mv_salary_weighted_ratio()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_salary_weighted_ratio;\r\nEND;\r\n$function$;",
  "refresh_mv_tech": "CREATE OR REPLACE FUNCTION public.refresh_mv_tech()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_tech;\r\nEND;\r\n$function$;",
  "refresh_mv_tech_category": "CREATE OR REPLACE FUNCTION public.refresh_mv_tech_category()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_tech_category;\r\nEND;\r\n$function$;",
  "refresh_mv_tech_combo_stats": "CREATE OR REPLACE FUNCTION public.refresh_mv_tech_combo_stats()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_tech_combo_stats;\r\nEND;\r\n$function$;",
  "refresh_mv_tech_ranking": "CREATE OR REPLACE FUNCTION public.refresh_mv_tech_ranking()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_tech_ranking;\r\nEND;\r\n$function$;",
  "refresh_mv_tech_tags": "CREATE OR REPLACE FUNCTION public.refresh_mv_tech_tags()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\n SET search_path TO 'public'\r\nAS $function$\r\nBEGIN\r\n  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_tech_tags;\r\nEND;\r\n$function$;",
  "reset_keywords": "CREATE OR REPLACE FUNCTION public.reset_keywords()\r\n RETURNS void\r\n LANGUAGE plpgsql\r\n SECURITY DEFINER\r\nAS $function$BEGIN\r\n  ALTER TABLE tech_keyword\r\n    DROP CONSTRAINT IF EXISTS tech_keyword_mapping_keyword_fkey;\r\n\r\n  TRUNCATE TABLE keyword;\r\n\r\n  INSERT INTO keyword (id, count)\r\n  SELECT kw, COUNT(*) AS count\r\n  FROM job_keyword, UNNEST(keywords) AS kw\r\n  GROUP BY kw\r\n\r\n  UNION ALL\r\n\r\n  SELECT k.keyword, 1\r\n  FROM tech_keyword k\r\n  WHERE k.keyword NOT IN (\r\n    SELECT DISTINCT kw\r\n    FROM job_keyword, UNNEST(keywords) AS kw\r\n  );\r\n\r\n  ALTER TABLE tech_keyword\r\n    ADD CONSTRAINT tech_keyword_mapping_keyword_fkey\r\n    FOREIGN KEY (keyword) REFERENCES keyword(id);\r\nEND;$function$;",
